<?php get_header(); while(have_posts()): the_post(); $u=get_post_meta(get_the_ID(),'_wdl_file_url',true); $pdf=get_post_meta(get_the_ID(),'_wdl_pdf_viewer',true); ?><div class="wdl-single"><h1><?php the_title();?></h1><?php the_content(); if($u && $pdf && 'pdf'===strtolower(pathinfo($u,PATHINFO_EXTENSION))){ $file_url=$u; $height=WDL_Settings::get_option('pdf_height',700); include WDL_PLUGIN_DIR.'templates/pdf-viewer.php'; } if($u):?><p><a class="wdl-button wdl-button-download" href="<?php echo esc_url($u);?>" download>Скачать</a></p><?php endif;?></div><?php endwhile; get_footer();
